/**
 * ACPX Mission Type Definitions
 * Minimal contract types for fresh mission creation.
 */

/** Mission status lifecycle */
export enum MissionStatus {
  Pending = "pending",
  Active = "active",
  Paused = "paused",
  Completed = "completed",
  Failed = "failed",
}

/** Core mission metadata */
export interface MissionMetadata {
  name: string;
  description?: string;
  tags?: string[];
  priority?: "low" | "medium" | "high";
  createdAt?: string;
  updatedAt?: string;
}

/** Mission execution context */
export interface MissionContext {
  missionId: string;
  status: MissionStatus;
  metadata: MissionMetadata;
  payload?: unknown;
}

/** Fresh mission creation payload */
export interface Mission extends MissionContext {
  status: MissionStatus.Pending;
}

/** Mission creation options */
export type MissionCreateInput = Omit<Mission, "missionId" | "status" | "metadata"> & {
  metadata?: Partial<MissionMetadata>;
};

